def unique_stocks():
    """回傳所有 ETF 去重後的成分股代碼清單"""
    seen = set()
    for v in ETF_HOLDINGS.values():
        for s in v['stocks']:
            seen.add(s)
    return sorted(seen)

def stocks_by_etf():
    """回傳 {etf_code: [stock_codes]}"""
    return {k: v['stocks'] for k, v in ETF_HOLDINGS.items()}

def etf_names():
    """回傳 {etf_code: name}"""
    return {k: v['name'] for k, v in ETF_HOLDINGS.items()}
